class Solution {
    public int getMaxRepetitions(String s1, int n1, String s2, int n2) {
        int m = 0, i = 0, j = 0;
        int[] count = new int[s2.length()];
        while (m < n1) {
            if (s2.charAt(j) == s1.charAt(i)) {
                count[j]++;
                i++;
                if (i == s1.length()) {
                    i = 0;
                    m++;
                }
                j = (j + 1) % s2.length();
            } else {
                j = 0;
            }
        }
        return m / n2;
    }
}
```

